  const mockTasks = [
    { id: 'task-1', title: 'Task 1', difficulty: 'easy', description: 'Desc 1', version: '1.0', status: 'published' as const },
    { id: 'task-2', title: 'Task 2', difficulty: 'medium', description: 'Desc 2', version: '1.0', status: 'draft' as const },
    { id: 'task-3', title: 'Task 3', difficulty: 'hard', description: 'Desc 3', version: '1.0', status: 'review' as const },
    { id: 'task-4', title: 'Task 4', difficulty: 'easy', description: 'Desc 4', version: '1.0', status: 'draft' as const },
  ];

  it('should return all tasks when no filters provided', async () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    vi.mocked(getTasks).mockResolvedValue(mockTasks as any);

    const request = new NextRequest('http://localhost/api/tasks');
    const response = await tasksHandler(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.count).toBe(4);
    expect(data.tasks).toHaveLength(4);
  });

  it('should filter tasks by difficulty', async () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    vi.mocked(getTasks).mockResolvedValue(mockTasks as any);

    const request = new NextRequest('http://localhost/api/tasks?difficulty=medium');
    const response = await tasksHandler(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.count).toBe(1);
    expect(data.tasks[0].id).toBe('task-2');
  });

  it('should filter tasks by status', async () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    vi.mocked(getTasks).mockResolvedValue(mockTasks as any);

    const request = new NextRequest('http://localhost/api/tasks?status=draft');
    const response = await tasksHandler(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.count).toBe(2);
    expect(data.tasks.every((t: { status: string }) => t.status === 'draft')).toBe(true);
  });

  it('should filter tasks by status review', async () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    vi.mocked(getTasks).mockResolvedValue(mockTasks as any);

    const request = new NextRequest('http://localhost/api/tasks?status=review');
    const response = await tasksHandler(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.count).toBe(1);
    expect(data.tasks[0].status).toBe('review');
  });

  it('should filter tasks by status published', async () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    vi.mocked(getTasks).mockResolvedValue(mockTasks as any);

    const request = new NextRequest('http://localhost/api/tasks?status=published');
    const response = await tasksHandler(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.count).toBe(1);
    expect(data.tasks[0].status).toBe('published');
  });

  it('should ignore invalid status values', async () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    vi.mocked(getTasks).mockResolvedValue(mockTasks as any);

    const request = new NextRequest('http://localhost/api/tasks?status=invalid');
    const response = await tasksHandler(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.count).toBe(4);
  });

  it('should combine difficulty and status filters', async () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    vi.mocked(getTasks).mockResolvedValue(mockTasks as any);

    const request = new NextRequest('http://localhost/api/tasks?difficulty=easy&status=draft');
    const response = await tasksHandler(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.count).toBe(1);
    expect(data.tasks[0].id).toBe('task-4');
  });

  it('should return empty array when combined filters match nothing', async () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    vi.mocked(getTasks).mockResolvedValue(mockTasks as any);

    const request = new NextRequest('http://localhost/api/tasks?difficulty=hard&status=published');
    const response = await tasksHandler(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.count).toBe(0);
    expect(data.tasks).toHaveLength(0);
  });
});

